import{_ as a,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Create Ad Links","description":"","frontmatter":{"title":"Create Ad Links","slug":"ad-links"},"headers":[],"relativePath":"marketer-hub/ad-links.md","filePath":"marketer-hub/ad-links.md"}'),r={name:"marketer-hub/ad-links.md"};function o(s,e,l,d,h,p){return t(),n("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A Branch Link is the vehicle that ensures seamless user experiences while also providing you with full attribution and analytics across email, referrals, paid advertising, social, organic search, and desktop-to-mobile.</p><p>If you are running paid advertising campaigns, you&#39;ll want to create a Branch Ad Link so we can accurately attribute resulting app conversions to the appropriate advertising partner. Branch Ad Links support deferred deep linking, Android App Links, and iOS Universal Links, as well as web and app conversions.</p><h2 id="create-an-ad-link" tabindex="-1">Create an Ad Link <a class="header-anchor" href="#create-an-ad-link" aria-label="Permalink to &quot;Create an Ad Link&quot;">​</a></h2><p>As all Branch Ad Links are uniquely built to a specific advertising partner, you can only create an Ad Link for enabled ad partners. To create a Branch Ad Link:</p><h3 id="_1-select-ad-format" tabindex="-1">1. Select Ad Format <a class="header-anchor" href="#_1-select-ad-format" aria-label="Permalink to &quot;1. Select Ad Format&quot;">​</a></h3><ol><li><p>Navigate to <a href="https://branch.dashboard.branch.io/quick-links/manager" target="_blank" rel="noreferrer">LinkHub</a> in the Branch Dashboard. Click the <strong>+</strong> <strong>Create Link</strong> button on the upper right-hand corner, then select <strong>Ad Link</strong>.</p></li><li><p>For <strong>Link Type</strong>, select one of the following ad formats:</p></li></ol><ul><li><p>App Only</p><ul><li><strong>App Install or Engagement</strong></li></ul></li><li><p>Cross-Platform Display</p><ul><li><strong>Display Link</strong></li><li><strong>Search Link</strong></li></ul></li></ul><ol start="3"><li>Click <strong>Continue</strong></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>For App Install or App Engagement campaigns, you&#39;ll want to select the App Only format. For Search or Display campaigns where the user should go to web if they don&#39;t have the app, then you should select Cross-Platform Search or Cross-Platform Display.</p></div><h3 id="_2-define-ad-link-domain-and-ad-partner" tabindex="-1">2. Define Ad Link domain and ad partner <a class="header-anchor" href="#_2-define-ad-link-domain-and-ad-partner" aria-label="Permalink to &quot;2. Define Ad Link domain and ad partner&quot;">​</a></h3><p>In the <strong>Define</strong> section, complete the following:</p><ol><li>Name your link.</li><li>Select the ad partner that the link is for.</li><li>Click <strong>Configure Options</strong> when you are done.</li></ol><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Branch Ad Links all use the domain <code>app.link</code> for the URL, regardless of whether you have a custom domain registered with your account. This is because the user will not see the URL and it allows for fewer redirects.</p></div><h3 id="_3-configuring-options" tabindex="-1">3. Configuring Options <a class="header-anchor" href="#_3-configuring-options" aria-label="Permalink to &quot;3. Configuring Options&quot;">​</a></h3><p>In the <strong>Configure Options</strong> section, please provide the following:</p><ol><li>Define your <strong>Link Alias</strong>. Note that this cannot be changed after you create the Ad Link!</li><li>Provide any of the following if applicable:</li></ol><details><summary>Analytics Tags</summary><p>It&#39;s easier to slice your data in our analytics platform if you properly assign analytics parameters to your link. Channels generally correspond to ad networks, and Campaigns correspond to marketing initiatives that you&#39;re launching. For example: Channel: &quot;YouTube&quot;, Campaign: &quot;Summer 2017 Shoe Discounts.&quot;</p></details><details><summary>Redirects</summary><p>The Redirect tab allows you to override your default redirects - as set in Link Settings - and direct users to specific locations if the app is not installs.</p><ul><li><p><strong>Default Redirect</strong> - Set at the account level within Link Settings. Typically set to the relevant mobile stores</p></li><li><p><strong>Web URL</strong> - Send users to a specific web page if they don’t have to the app to avoid any unexpected flow to the app store</p></li><li><p>Deepview - Send users to a specific Deepviewkm you may have created under the Web to App &gt; Deepview section. Copy the key and paste it into the text box. Useful if you want to present the user with a preview of the content before taking them directly to the app store. Should not be set for Desktop option.</p><p>Note: If you want to always <strong>force the app to open</strong>, even if it risks showing an error message when the app is not installed, make sure the <strong>URI Scheme Deep Link Mode</strong> in your <strong>Link Settings</strong> is set to <code>Aggressive</code>. By changing this setting, Branch will force open the app for all users.</p></li></ul></details><details><summary>Link Data</summary><p>The Link Data tab allows you to include additional data to your links to be used not only for contextual deep linking, but for passing additional attributes you or your ad partner may require.</p><p>To add additional data - i.e. key-value pairs - to your Ad Link:</p><ol><li><p>Click <strong>+More Data</strong>.</p></li><li><p>Input the parameter name in the <strong>Key</strong> field and its corresponding value or macro in the <strong>Value</strong> field.</p><ul><li>If you wish to <strong>Force Open the App</strong>, even if it risks showing an error message when the app is not installed, add <code>uri_redirect_mode</code> in the <strong>Key</strong> field and <code>2</code> in the <strong>Value</strong> field. By adding this key-value pair, only those who click on this link will have the app forced open regardless.</li></ul></li></ol></details><ol start="3"><li>Click <strong>Create Link Now</strong> when you&#39;re done. You&#39;ll then be brought to the last phase of creating a link - <strong>Validate &amp; Share</strong>.</li></ol><p>.png &quot;configure_options.png&quot;)</p><h3 id="_4-validate-share" tabindex="-1">4. Validate &amp; Share <a class="header-anchor" href="#_4-validate-share" aria-label="Permalink to &quot;4. Validate &amp; Share&quot;">​</a></h3><h4 id="validate" tabindex="-1">Validate <a class="header-anchor" href="#validate" aria-label="Permalink to &quot;Validate&quot;">​</a></h4><p>Once you&#39;ve created your Ad link, we will automatically validate its settings to make sure your link works as you expect.</p><p>If we recognize an issue with your ad link, you will see an error message with what needs to be fixed before sharing your link. Click on the error message to go back and fix the offending setting. Once no issues exist, you should only see green checks next to your links settings.</p><p>.png &quot;Validation.png&quot;)</p><h4 id="share" tabindex="-1">Share <a class="header-anchor" href="#share" aria-label="Permalink to &quot;Share&quot;">​</a></h4><p>We provide you with a Branch Link for both clicks and impressions. Simply copy and paste the links in the tracking section of your campaign tool or email to your Ad Partner&#39;s account manager.</p><p>You can also text yourself (or someone else) the link by providing a phone number and clicking Send.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>How are Short Links different from Ad Links?</summary><h4 id="functionality" tabindex="-1">Functionality <a class="header-anchor" href="#functionality" aria-label="Permalink to &quot;Functionality&quot;">​</a></h4><p>Functionally, Short Links and Ad Links work the same -- they both attribute in the same fashion (outside of the iOS ATT restrictions -- Short Links are “owned” links so these can still attribute downstream data) and route users in the same way to the destinations set up on the links.</p><p><a href="https://help.branch.io/v1/docs/ad-links" target="_blank" rel="noreferrer">Ad Links</a> are primarily designed for working with ad partners, so they’ll include a $3p value that designates the specific ad partner, and for integrated partners, they’ll include a much longer URL string that includes macros for the partner to pass through dynamic values like campaign name, etc. Additionally, Ad Links will automatically implement ATT-compliant behavior on iOS. <a href="https://help.branch.io/faq/docs/how-do-we-configure-a-non-ads-link-to-use-branchs-att-compliant-behavior" target="_blank" rel="noreferrer">This is not the case for Short Links</a>.</p><p><a href="https://help.branch.io/v1/docs/create-quick-links" target="_blank" rel="noreferrer">Short Links</a> are for “owned” placements (non-paid-ads use cases in general) and cases where the link may be visible, and Ad Links are designed for paid ads where users aren’t expected to see the link itself as well as where dynamic data is expected to be passed.</p><p>For a list of what Branch Link to use for a specific use case, see below:</p><table tabindex="0"><thead><tr><th>Branch Link</th><th>Use Cases</th></tr></thead><tbody><tr><td>Short Link</td><td>- Quick QR Code generator (via Branch Dashboard). - Custom Vanity/Alias Link. ex. <code>branchster.app.link/discount2022``df</code></td></tr><tr><td>Ad Link</td><td>Ad Partner Campaign. ex. Facebook Ad Link: <code>https://branchster.app.link/J9g9yuoTPqb?%243p=a_facebook&amp;%24deeplink_no_attribution=true</code></td></tr></tbody></table><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Branch Ad Link creation is included in our Performance Essentials <a href="https://help.branch.io/docs/products" target="_blank" rel="noreferrer">product tier</a>, while access to the <a href="https://help.branch.io/v1-api/apidocs/quick-links-api" target="_blank" rel="noreferrer">Short Links API</a> is limited to Engagement Pro customers.</p></details><details><summary>Can I create a QR code for Ad Links?</summary><p>QR Codes are currently only supported for Short Links.</p><p>Ad Links are dynamic links with macros, which are filled in by the ad network.</p><p>The macros change dynamically depending on the campaign, so one QR code cannot be generated for the Ad Links with macros.</p></details><details><summary>Why am I seeing the following error: “The link is not formatted properly”?</summary><p>The Ad Link that you generate in Branch is a tracking link that needs to be provided to your ad partner, who will then use this link to create ad campaigns.</p><p>You are seeing an error when directly clicking on this link as this will not have values for the Parameters on the link. You can test this link by adding the parameters to the ad link manually.</p><p>For example, if the platform is iOS, remove AAID parameter from the link and append the device ID value for IDFA as: &#39;%24idfa=xxxxxx&#39;. Similarly, for Android, remove the IDFA parameter from the link and append the device id value for AAID.</p></details>',34)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
